const agents = Array.isArray($input.first().json) ? $input.first().json : ($input.first().json.agents || $input.first().json.data || []);
const lines = agents.map((a) => {
  const name = a.name || a.slug || a.id || 'agent';
  const count = a.conversations_24h ?? a.conversationCount ?? a.count ?? 'n/a';
  return `- *${name}*: ${count} conversation(s) in the last 24h`;
});
const text = lines.length
  ? `SeldonFrame daily digest\n${lines.join('\n')}`
  : 'SeldonFrame daily digest\nNo agent conversation data returned for this period.';
return [{ json: { text } }];
